"use client";

import { useRouter } from "next/navigation";

export default function Header({ onSearch }: { onSearch: (q: string) => void }) {
  const router = useRouter();

  return (
    <header className="w-full bg-zinc-900 border-b border-zinc-800 p-4 flex justify-between items-center mb-6">
      <h1 className="text-red-600 text-2xl font-bold cursor-pointer" onClick={() => router.push("/")}>
        CINE LOCAL
      </h1>

      <input
        type="text"
        placeholder="Search movies…"
        className="bg-zinc-800 px-3 py-1 rounded border border-zinc-700 w-64"
        onChange={(e) => onSearch(e.target.value)}
      />

      <div className="flex gap-4">
        <button onClick={() => router.push("/login")}>Login</button>
        <button onClick={() => router.push("/signup")}>Signup</button>
      </div>
    </header>
  );
}
